function extractJson(text) {
  if (!text) return null;
  const stripped = String(text)
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) return null;
  return stripped.slice(start, end + 1);
}

function getAiText(item) {
  const o = item.json.output;
  if (o && Array.isArray(o) && o[0]?.content?.[0]?.text) {
    return o[0].content[0].text;
  }
  if (Array.isArray(item.json.content)) {
    const text = item.json.content
      .map(entry => entry?.text || entry?.content || '')
      .filter(Boolean)
      .join('\n');
    if (text) return text;
  }
  return (
    item.json.text ||
    item.json.output_text ||
    item.json.message?.content ||
    item.json.choices?.[0]?.message?.content ||
    ''
  );
}

function asArray(value) {
  if (Array.isArray(value)) {
    return value
      .filter(v => v !== null && v !== undefined && String(v).trim() !== '')
      .map(v => String(v).trim());
  }

  if (typeof value === 'string' && value.trim() !== '') {
    const t = value.trim();

    try {
      const parsed = JSON.parse(t);
      if (Array.isArray(parsed)) {
        return parsed.filter(Boolean).map(v => String(v).trim());
      }
    } catch (e) {}

    return t
      .split(/\s*\|\s*/)
      .filter(Boolean)
      .map(v => String(v).trim());
  }

  return [];
}

function cleanText(value) {
  return String(value == null ? '' : value)
    .replace(/\r/g, '')
    .trim();
}

function normalizeKey(value) {
  return cleanText(value).toLowerCase();
}

function normalizeVn(value) {
  return cleanText(value).replace(/\s+/g, '');
}

function isTechnicalPlaceholder(value) {
  const text = cleanText(value);
  if (!text) return true;

  const normalized = text
    .toLowerCase()
    .replace(/[„“”"'`´]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  if (['null', 'undefined', 'n/a', 'na', 'leer'].includes(normalized)) {
    return true;
  }

  return (
    /^\(?dokumentlinks? gefunden,?\s*aber kein dokumenttext extrahierbar\)?[.!]?$/i.test(text) ||
    /^\(?kein dokumenttext extrahierbar\)?[.!]?$/i.test(text) ||
    /^\(?keine dokumenttexte? extrahierbar\)?[.!]?$/i.test(text) ||
    /^\(?kein verwertbarer dokumenttext\)?[.!]?$/i.test(text) ||
    /^vorgangsseite\b.*(?:fehler|nicht erreichbar|nicht geladen|leer)/i.test(text) ||
    /^(?:fehler|error|download fehlgeschlagen|extraktion fehlgeschlagen)\b/i.test(text)
  );
}

function getNodeItems(nodeName) {
  try {
    const nodeItems = $(nodeName).all(0, $runIndex);
    return Array.isArray(nodeItems) ? nodeItems : [];
  } catch (e) {
    return [];
  }
}

function rowUsable(candidate) {
  if (!candidate) return false;
  const combinedText = cleanText(candidate.combinedText);
  return combinedText.length >= 300 && !isTechnicalPlaceholder(combinedText);
}

function scoreRow(candidate, expectedKey, expectedVn, expectedTitle) {
  if (!candidate) return -999;
  let score = 0;

  const key = normalizeKey(candidate.vorgangKey);
  const vn = normalizeVn(candidate.vorgangsnummer);
  const title = cleanText(candidate.title).toLowerCase();

  if (expectedKey) score += key === expectedKey ? 1000 : -1000;
  if (expectedVn) score += vn === expectedVn ? 500 : -500;
  if (expectedTitle && title && title === expectedTitle.toLowerCase()) score += 100;

  if (candidate.summaryInputOk === true) score += 50;
  if (rowUsable(candidate)) score += 25;
  if (cleanText(candidate.summaryText).length > 50) score += 5;

  return score;
}

function getSummarySourceRow(summary) {
  // WICHTIGER FIX:
  // Die KI-Zusammenfassung muss ihren eigenen VorgangKey/Vorgangsnummer zurückgeben.
  // Dadurch wird verhindert, dass bei mehreren Items die KI-Antwort eines Vorgangs
  // mit dem Datensatz eines anderen Vorgangs gespeichert wird.
  const expectedKey = normalizeKey(summary?.vorgangKey || summary?.sourceVorgangKey || '');
  const expectedVn = normalizeVn(summary?.vorgangsnummer || summary?.sourceVorgangsnummer || '');
  const expectedTitle = cleanText(summary?.title || summary?.sourceTitle || '');

  const candidateNodes = [
    'Prepare Summary Input',
    'Prüfe Summary Input',
    'NC Aggregiere Texte',
    'Prüfe vorhandenen combinedText',
    'Prüfe vorhandene Summary',
    'Loop Vorgänge'
  ];

  const candidates = [];
  for (const nodeName of candidateNodes) {
    const nodeItems = getNodeItems(nodeName);
    for (let i = 0; i < nodeItems.length; i++) {
      const row = nodeItems[i]?.json || null;
      if (!row) continue;
      candidates.push({
        nodeName,
        itemIndex: i,
        row,
        score: scoreRow(row, expectedKey, expectedVn, expectedTitle)
      });
    }
  }

  // Bei neuer Prompt-Version müssen diese Metadaten vorhanden sein.
  // Ohne sie wird nur noch dann fortgesetzt, wenn wirklich exakt ein eindeutiger
  // Vorgang im Kontext liegt. Sonst lieber blockieren als falsch speichern.
  if (!expectedKey && !expectedVn) {
    const keys = Array.from(new Set(
      candidates
        .map(c => normalizeKey(c.row.vorgangKey))
        .filter(Boolean)
    ));

    if (keys.length === 1) {
      const row = candidates
        .filter(c => normalizeKey(c.row.vorgangKey) === keys[0])
        .sort((a, b) => b.score - a.score)[0]?.row;
      if (row) return row;
    }

    throw new Error(
      'Parse Summary JSON blockiert: KI-Antwort enthält keinen vorgangKey/vorgangsnummer und der Kontext ist nicht eindeutig. ' +
      'Damit würde eine falsche Zuordnung zwischen Titel und Zusammenfassung drohen.'
    );
  }

  const matches = candidates
    .filter(c => c.score > 0)
    .sort((a, b) => b.score - a.score);

  if (!matches.length) {
    throw new Error(
      'Parse Summary JSON blockiert: Kein Quelldatensatz passt zur KI-Antwort. ' +
      'KI vorgangKey="' + (summary?.vorgangKey || '') + '", vorgangsnummer="' + (summary?.vorgangsnummer || '') + '".'
    );
  }

  const best = matches[0].row;

  if (expectedKey && normalizeKey(best.vorgangKey) !== expectedKey) {
    throw new Error(
      'Parse Summary JSON blockiert: VorgangKey-Konflikt. KI=' +
      expectedKey + ', Datensatz=' + normalizeKey(best.vorgangKey)
    );
  }

  if (expectedVn && normalizeVn(best.vorgangsnummer) !== expectedVn) {
    throw new Error(
      'Parse Summary JSON blockiert: Vorgangsnummer-Konflikt. KI=' +
      expectedVn + ', Datensatz=' + normalizeVn(best.vorgangsnummer)
    );
  }

  return best;
}

const item = $input.item;
const rawText = getAiText(item);
const jsonStr = extractJson(rawText);

let summary = null;
if (jsonStr) {
  try {
    summary = JSON.parse(jsonStr);
  } catch (e) {}
}

if (!summary) {
  // Kein sicherer Kontext ohne parsebare KI-Antwort.
  return [{
    json: {
      summaryParseError: true,
      rawSummaryText: rawText,
      summaryJson: '{}',
      summaryText: '',
      summarySentences: '[]',
      thema: '',
      betroffene: '[]',
      kostenHaushalt: '',
      buergerwirkung: '',
      offenePunkte: '[]',
      unsicherheitenSummary: '[]',
      status: 'summary_parse_error'
    }
  }];
}

const row = getSummarySourceRow(summary);

// combinedText aus dem tatsächlich verwendeten KI-Eingang erhalten.
// Dadurch wird ein per Nextcloud/Tika erzeugter Text später in der DataTable gespeichert.
const combinedText = cleanText(row.combinedText);
const combinedTextLength = combinedText.length;

const summarySentences = asArray(summary.summarySentences);
const betroffene = asArray(summary.betroffene);
const offenePunkte = asArray(summary.offenePunkte);
const unsicherheiten = asArray(summary.unsicherheiten);

return [{
  json: {
    ...row,
    combinedText,
    combinedTextLength,
    summaryParseError: false,
    rawSummaryText: '',
    summaryJson: JSON.stringify(summary),
    summarySourceVorgangKey: summary.vorgangKey || '',
    summarySourceVorgangsnummer: summary.vorgangsnummer || '',
    summarySourceTitle: summary.title || '',
    summaryText: summary.summaryText || summarySentences.join(' '),
    summarySentences: JSON.stringify(summarySentences),
    thema: summary.thema || '',
    betroffene: JSON.stringify(betroffene),
    kostenHaushalt: summary.kostenHaushalt || '',
    buergerwirkung: summary.buergerwirkung || '',
    offenePunkte: JSON.stringify(offenePunkte),
    unsicherheitenSummary: JSON.stringify(unsicherheiten)
  }
}];

// ── Branch-sicherer Datenzugriff (BRANCH_SAFE_SUMMARY_FIX) ──────────────────
// Build Summary Message wird vom TRUE-Pfad (vorhandene Summary, Speichere Summary
// wurde NICHT ausgeführt) und vom FALSE-Pfad (neue Summary) erreicht.
// Daher darf $('Speichere Summary') NICHT direkt aufgerufen werden.
function getNodeJsonIfExecuted(nodeName) {
  try {
    return $(nodeName).item.json || {};
  } catch (e) {
    return {};
  }
}

// Loop Vorgänge ist normalerweise die Basisquelle für Vorgangsfelder.
// V12.12: Wenn der Loop-Kontext nicht zum aktuellen Input passt, wird er verworfen.
// Sonst können Titel und Zusammenfassung aus unterschiedlichen Vorgängen gemischt werden.
let baseData = getNodeJsonIfExecuted('Loop Vorgänge');

// Aktueller Input hat Vorrang (enthält Summary-Felder des jeweiligen Pfads)
const currentData = $input.item.json || {};

function _normKey(v) { return String(v || '').trim().toLowerCase(); }
function _normVn(v) { return String(v || '').trim().replace(/\s+/g, ''); }

const _currentKey = _normKey(currentData.vorgangKey);
const _baseKey = _normKey(baseData.vorgangKey);
const _currentVn = _normVn(currentData.vorgangsnummer);
const _baseVn = _normVn(baseData.vorgangsnummer);

if ((_currentKey && _baseKey && _currentKey !== _baseKey) ||
    (_currentVn && _baseVn && _currentVn !== _baseVn)) {
  baseData = {};
}

// Merge: currentData überschreibt baseData; leere currentData-Felder
// werden durch baseData aufgefüllt.
const data = { ...baseData, ...currentData };

// Explizite Fallbacks für kritische Summary-Felder, damit kein gefüllter
// Wert durch einen leeren currentData-Eintrag verloren geht.
const summaryText   = String(currentData.summaryText   || baseData.summaryText   || '').trim();
const summaryJson   = currentData.summaryJson   || baseData.summaryJson   || '';
const summarySentences = currentData.summarySentences || baseData.summarySentences || [];
const thema         = currentData.thema         || baseData.thema         || '';
const betroffeneRaw = currentData.betroffene    || baseData.betroffene    || '';
const kostenHaushalt  = currentData.kostenHaushalt  || baseData.kostenHaushalt  || '';
const buergerwirkung  = currentData.buergerwirkung  || baseData.buergerwirkung  || '';
const offenePunkteRaw = currentData.offenePunkte   || baseData.offenePunkte   || '';
const unsicherheitenRaw = currentData.unsicherheitenSummary || baseData.unsicherheitenSummary || '';

// Basis-Vorgangsfelder aus data (immer vorhanden)
const j = {
  ...data,
  summaryText,
  summaryJson,
  summarySentences,
  thema,
  betroffene: betroffeneRaw,
  kostenHaushalt,
  buergerwirkung,
  offenePunkte: offenePunkteRaw,
  unsicherheitenSummary: unsicherheitenRaw
};

// ── Metadaten-Schutzprüfung (B4) ─────────────────────────────────────────────
const _guardTitle = String(j.title || '').trim();
const _guardVorgangsnummer = String(j.vorgangsnummer || '').trim();
const _HTTP_ERROR_TITLE_RE_G = /^\s*(?:400[\s:-]+bad\s+request|401[\s:-]+unauthorized|403[\s:-]+forbidden|404[\s:-]+not\s+found|408[\s:-]+request\s+time[- ]?out|429[\s:-]+too\s+many\s+requests|500[\s:-]+internal\s+server\s+error|501[\s:-]+not\s+implemented|502[\s:-]+bad\s+gateway|503[\s:-]+service\s+unavailable|504[\s:-]+gateway\s*time[- ]?out)\s*$/i;
const _TECH_PHRASE_RE_G = /gateway\s*time[- ]?out|bad\s+gateway|service\s+unavailable|internal\s+server\s+error|request\s+time[- ]?out|upstream\s+timed\s+out|proxy\s+error|temporarily\s+unavailable|too\s+many\s+requests|serverfehler|nginx\s+error|cloudflare\s+error/i;

if (!_guardTitle || _HTTP_ERROR_TITLE_RE_G.test(_guardTitle) || _TECH_PHRASE_RE_G.test(_guardTitle)) {
  throw new Error('Matrix-Ausgabe blockiert: ungültige Vorgangsmetadaten. Titel: "' + _guardTitle + '"');
}
if (!/^\d{4}\/\d+(?:-\d+)?$/.test(_guardVorgangsnummer)) {
  throw new Error('Matrix-Ausgabe blockiert: ungültige Vorgangsnummer: "' + _guardVorgangsnummer + '"');
}
// ── Ende Schutzprüfung ─────────────────────────────────────────────────────

function parseList(value) {
  if (Array.isArray(value)) return value.filter(Boolean).map(v => String(v).trim());
  if (value === null || value === undefined || value === '') return [];
  const t = String(value).trim();
  if (!t) return [];
  try {
    const parsed = JSON.parse(t);
    if (Array.isArray(parsed)) return parsed.filter(Boolean).map(v => String(v).trim());
  } catch (e) {}
  return t.split(/\s*\|\s*/).filter(Boolean).map(v => String(v).trim());
}

if (j.summaryParseError) {
  const msg =
    `⚠️ [PARSE-FEHLER Zusammenfassung] ${j.title || ''}\n` +
    `${j.allrisUrl || ''}\n\n` +
    `Die KI-Antwort konnte nicht als JSON gelesen werden. Bitte rawSummaryText prüfen.`;

  return [{
    json: {
      ...j,
      summaryMessage: msg,
      txnId: 'err_sum_' + Date.now() + '_' + (j.vorgangKey || '').replace(/[^a-zA-Z0-9]/g,'').substring(0,10)
    }
  }];
}

const sentences    = parseList(j.summarySentences);
const betroffene   = parseList(j.betroffene);
const offenePunkte = parseList(j.offenePunkte);
const unsicherheiten = parseList(j.unsicherheitenSummary);


// ── Vorgangskette-Block für Matrix (nur bei Folgevorgängen) ──────────────────
let vorgangsketteBlock = '';

if (j.istFolgevorgang === true || String(j.istFolgevorgang || '').trim() === 'true') {
  const details = Array.isArray(j.vorgangsketteDetails) ? j.vorgangsketteDetails : [];
  const fehlend = Array.isArray(j.fehlendeVorherigeVorgaenge) ? j.fehlendeVorherigeVorgaenge : [];
  const vollstaendig = j.vorgangsketteVollstaendig === true;

  let ketteLines = ['', 'Bezug zu vorherigen Vorgängen:', ''];
  ketteLines.push(`* Stammvorgang: ${j.stammVorgangsnummer || ''}`);

  const berücksichtigt = details.filter(d => d.gefunden && d.kontextVerwendet);
  const nichtBerücksichtigt = details.filter(d => d.gefunden && !d.kontextVerwendet);

  if (berücksichtigt.length > 0) {
    ketteLines.push('* Berücksichtigte Vorgänge:');
    for (const d of berücksichtigt) {
      const quelleText = d.kontextQuelle === 'summary'
        ? 'vorhandene Zusammenfassung'
        : 'Dokumenttext als Fallback';
      ketteLines.push(`  * ${d.vorgangsnummer} – ${quelleText}`);
    }
  }

  if (nichtBerücksichtigt.length > 0) {
    ketteLines.push('* Gefunden, aber in diesem Lauf nicht als Kontext verfügbar:');
    for (const d of nichtBerücksichtigt) {
      ketteLines.push(`  * ${d.vorgangsnummer}`);
    }
  }

  if (fehlend.length > 0) {
    ketteLines.push('* Fehlende Vorgänge:');
    for (const vn of fehlend) {
      ketteLines.push(`  * ${vn}`);
    }
  }

  ketteLines.push(`* Vorgangskette vollständig: ${vollstaendig ? 'Ja' : 'Nein'}`);
  vorgangsketteBlock = ketteLines.join('\n');
}

let msg = `📄 Neue ALLRIS-Vorlage\n\n`;
msg += `Titel:\n${j.title || ''}\n\n`;
msg += `Vorgangsnummer:\n${j.vorgangsnummer || ''}\n\n`;
msg += `Link:\n${j.allrisUrl || ''}\n\n`;

if (vorgangsketteBlock) { msg += vorgangsketteBlock + '\n\n'; }

msg += `Kurzfassung:\n`;

let summaryBlock = '';

if (j.summaryText && String(j.summaryText).trim()) {
  summaryBlock = String(j.summaryText).trim();
} else if (sentences.length > 0) {
  summaryBlock = sentences.join(' ');
} else {
  summaryBlock = '(keine Zusammenfassung)';
}

summaryBlock = summaryBlock
  .replace(/\r\n/g, '\n')
  .replace(/[ \t]+\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

msg += summaryBlock;

msg += `\n\nEinordnung:\n`;
msg += `- Thema: ${j.thema || '—'}\n`;
msg += `- Betroffene: ${betroffene.join(', ') || '—'}\n`;
msg += `- Kosten/Haushalt: ${j.kostenHaushalt || '—'}\n`;
msg += `- Bürgerwirkung: ${j.buergerwirkung || '—'}\n`;

if (offenePunkte.length > 0) {
  msg += `- Offene Punkte:\n` + offenePunkte.map(p => `  • ${p}`).join('\n') + '\n';
}

if (unsicherheiten.length > 0) {
  msg += `- Unsicherheiten:\n` + unsicherheiten.map(p => `  • ${p}`).join('\n') + '\n';
}

const txnId = 'sum_' + Date.now() + '_' + (j.vorgangKey || '').replace(/[^a-zA-Z0-9]/g,'').substring(0,10);

return [{
  json: {
    ...j,
    summaryMessage: msg,
    txnId
  }
}];

// n8n Code Node: "Parse Analyse JSON"
// Dieser Code ersetzt den bisherigen Code im Node vollständig.
//
// Zweck:
// 1. KI-Rohantwort aus "AI Analyse JSON" lesen
// 2. JSON daraus extrahieren
// 3. Ursprüngliche Vorgangsdaten aus "Prepare Analyse Input" zurückholen
// 4. Bewertung normalisieren
// 5. Visual Guard anwenden
// 6. NUR vorhandene DataTable-Spalten befüllen
//
// Keine neuen Spalten nötig.
// Detaildaten bleiben in:
// - analysisJson.sourceLock
// - analysisJson.visualAnchors
// - analysisJson.visualWorkflow
// - analysisJson.visualGuardErrors

function extractJson(text) {
  if (!text) return null;

  const stripped = String(text)
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();

  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');

  if (start === -1 || end === -1 || end <= start) return null;

  return stripped.slice(start, end + 1);
}

function getAiText(item) {
  const j = item.json || {};

  const o = j.output;
  if (o && Array.isArray(o) && o[0]?.content?.[0]?.text) {
    return o[0].content[0].text;
  }

  if (Array.isArray(j.content)) {
    const text = j.content
      .map(entry => entry?.text || entry?.content || '')
      .filter(Boolean)
      .join('\n');

    if (text) return text;
  }

  return (
    j.text ||
    j.output_text ||
    j.message?.content ||
    j.choices?.[0]?.message?.content ||
    ''
  );
}

function getNodeItems(nodeName) {
  try {
    const items = $(nodeName).all(0, $runIndex);
    return Array.isArray(items) ? items : [];
  } catch (e) {
    try {
      const items = $(nodeName).all();
      return Array.isArray(items) ? items : [];
    } catch (e2) {
      return [];
    }
  }
}

function getPrepareAnalyseRow() {
  const items = getNodeItems('Prepare Analyse Input');

  if (items.length === 1 && items[0]?.json) {
    return items[0].json;
  }

  try {
    const j = $('Prepare Analyse Input').item.json;
    if (j && Object.keys(j).length > 0) return j;
  } catch (e) {}

  if (items.length > 0 && items[0]?.json) {
    return items[0].json;
  }

  return {};
}

function safeStr(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

function normalizeText(v) {
  return safeStr(v)
    .toLowerCase()
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/ß/g, 'ss')
    .replace(/[„“”"'`´]/g, '')
    .replace(/[\-–—]/g, ' ')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;

  if (typeof v === 'string') {
    try {
      const p = JSON.parse(v);
      if (p && typeof p === 'object' && !Array.isArray(p)) return p;
    } catch (e) {}
  }

  return {};
}

function asArray(v) {
  if (Array.isArray(v)) {
    return v
      .filter(x => x !== null && x !== undefined && safeStr(x) !== '')
      .map(x => safeStr(x));
  }

  if (v === null || v === undefined || v === '') return [];

  if (typeof v === 'string') {
    const t = v.trim();
    if (!t) return [];

    try {
      const p = JSON.parse(t);
      if (Array.isArray(p)) {
        return p
          .filter(x => x !== null && x !== undefined && safeStr(x) !== '')
          .map(x => safeStr(x));
      }
    } catch (e) {}

    return t
      .split(/\s*\|\s*/)
      .map(x => safeStr(x))
      .filter(Boolean);
  }

  return [safeStr(v)].filter(Boolean);
}

function uniqueArray(arr) {
  const out = [];
  const seen = new Set();

  for (const item of asArray(arr)) {
    const key = normalizeText(item);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    out.push(item);
  }

  return out;
}

function hasValue(v) {
  if (Array.isArray(v)) return v.length > 0;
  if (v && typeof v === 'object') return Object.keys(v).length > 0;
  return safeStr(v).length > 0;
}

function pick(primary, fallback, fallback2 = '') {
  if (hasValue(primary)) return primary;
  if (hasValue(fallback)) return fallback;
  return fallback2;
}

function toNumber(v, fallback = 0) {
  const n = Number(String(v ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : fallback;
}

function toBool(v) {
  if (v === true || v === 1) return true;
  if (v === false || v === 0 || v === null || v === undefined) return false;

  const s = String(v).trim().toLowerCase();
  return ['true', '1', 'yes', 'ja', 'y'].includes(s);
}

function enumValue(v, allowed, fallback) {
  const s = safeStr(v).toUpperCase();
  return allowed.includes(s) ? s : fallback;
}

function clamp(n, min, max) {
  return Math.max(min, Math.min(max, n));
}

function atLeastSprengstoff(current, minimum) {
  const order = { KEINER: 0, GERING: 1, MITTEL: 2, HOCH: 3 };
  const reverse = ['KEINER', 'GERING', 'MITTEL', 'HOCH'];
  return reverse[Math.max(order[current] ?? 0, order[minimum] ?? 0)];
}

// ============================================================
// 1. KI-ANTWORT PARSEN
// ============================================================

const item = $input.item;
const rowData = getPrepareAnalyseRow();
const rawText = getAiText(item);
const jsonStr = extractJson(rawText);

let analysis = null;
let parseError = false;

if (jsonStr) {
  try {
    analysis = JSON.parse(jsonStr);
  } catch (e) {
    parseError = true;
  }
} else {
  parseError = true;
}

if (parseError || !analysis) {
  return [{
    json: {
      ...rowData,
      analysisParseError: true,
      rawAiText: rawText,
      analysisJson: '{}',

      relevantScore: 0,
      sprengstoff: 'KEINER',
      empfehlung: 'BEOBACHTEN',
      kommunikationspotenzial: 0,
      themes: '',
      matrixKurzbetreff: '[FEHLER] ' + (rowData.title || ''),
      ampel: '⚪',

      kurzfassung: '',
      kritischeNachfrage: '',
      begruendungBewertung: '',
      werProfitiert: '',
      werZahltOderTraegtNachteile: '',
      warumRelevant: '',
      belegbareFakten: '',
      unsicherheiten: '',
      warnsignale: '',

      instagramCarouselNoetig: false,

      visualStatus: 'analysis_error',
      instagramSharepicNoetig: false,
      visualDecisionReason: 'Analyse-JSON konnte nicht verarbeitet werden',
      visualNeeded: false,

      satireBrief: '',
      satireAngle: '',
      satirePunchlines: '[]',
      visualMetaphor: '',
      satireTarget: '',
      satireIntensity: 0,
      satireDoNotClaim: '[]',
      satireSafetyNote: '',

      satireWorkflowVersion: 'satire-parse-guard-existing-columns-v3',
      status: 'analysis_error'
    }
  }];
}

const s = analysis;

// ============================================================
// 2. SOURCELOCK UND VISUAL ANCHORS LESEN
// ============================================================

const nestedSourceLock = parseObj(s.sourceLock);
const nestedVisualAnchors = parseObj(s.visualAnchors);

let sourceLock = {
  sourceTopic: safeStr(pick(nestedSourceLock.sourceTopic, s.sourceTopic)),
  sourceConflict: safeStr(pick(nestedSourceLock.sourceConflict, s.sourceConflict)),
  requiredTerms: uniqueArray(pick(nestedSourceLock.requiredTerms, s.requiredTerms, [])),
  requiredObjects: uniqueArray(pick(nestedSourceLock.requiredObjects, s.requiredObjects, [])),
  requiredAction: safeStr(pick(nestedSourceLock.requiredAction, s.requiredAction)),
  affectedGroups: uniqueArray(pick(nestedSourceLock.affectedGroups, s.affectedGroups, [])),
  forbiddenDrift: uniqueArray(pick(nestedSourceLock.forbiddenDrift, s.forbiddenDrift, []))
};

let visualAnchors = {
  satireThemaKonkret: safeStr(pick(nestedVisualAnchors.satireThemaKonkret, s.satireThemaKonkret)),
  satireKonfliktKonkret: safeStr(pick(nestedVisualAnchors.satireKonfliktKonkret, s.satireKonfliktKonkret)),
  visualPflichtobjekte: uniqueArray(pick(nestedVisualAnchors.visualPflichtobjekte, s.visualPflichtobjekte, [])),
  visualPflichthandlung: safeStr(pick(nestedVisualAnchors.visualPflichthandlung, s.visualPflichthandlung)),
  visualBetroffene: uniqueArray(pick(nestedVisualAnchors.visualBetroffene, s.visualBetroffene, [])),
  visualOrt: safeStr(pick(nestedVisualAnchors.visualOrt, s.visualOrt || '')),
  visualUeberzeichnung: safeStr(pick(nestedVisualAnchors.visualUeberzeichnung, s.visualUeberzeichnung)),
  visualErkennungssatz: safeStr(pick(nestedVisualAnchors.visualErkennungssatz, s.visualErkennungssatz)),
  visualVerboteneErsatzmotive: uniqueArray(pick(nestedVisualAnchors.visualVerboteneErsatzmotive, s.visualVerboteneErsatzmotive, []))
};

// ============================================================
// 3. QUELLTEXT FÜR KONTEXT
// ============================================================

const sourceText = [
  rowData.title,
  rowData.vorgangsnummer,
  rowData.summaryText,
  rowData.thema,
  rowData.betroffene,
  rowData.kostenHaushalt,
  rowData.buergerwirkung,
  rowData.offenePunkte,
  rowData.unsicherheitenSummary,
  rowData.combinedText,
  rowData.analyseContext
].map(safeStr).join('\n');

const sourceNorm = normalizeText(sourceText);

// ============================================================
// 4. ENTSCHEIDUNGSFELDER NORMALISIEREN
// ============================================================

let relevanz = toNumber(s.relevanz, 0);
let kommunikationspotenzial = toNumber(s.kommunikationspotenzial, 0);

let sprengstoff = enumValue(
  s.sprengstoff,
  ['KEINER', 'GERING', 'MITTEL', 'HOCH'],
  'KEINER'
);

let empfehlung = enumValue(
  s.empfehlung,
  ['IGNORIEREN', 'BEOBACHTEN', 'REAGIEREN'],
  'BEOBACHTEN'
);

const ungleichFlag =
  s.ungleichbehandlungErkannt === true ||
  s.willkuerErkannt === true ||
  s.doppelstandardErkannt === true;

if (ungleichFlag) {
  relevanz = Math.max(relevanz, 8);
  kommunikationspotenzial = Math.max(kommunikationspotenzial, 8);
  sprengstoff = atLeastSprengstoff(sprengstoff, 'MITTEL');
  empfehlung = 'REAGIEREN';
}

if (
  (relevanz >= 7 && kommunikationspotenzial >= 7) ||
  sprengstoff === 'HOCH' ||
  (sprengstoff === 'MITTEL' && relevanz >= 7) ||
  (s.oeffentlicheGelderBetroffen === true && relevanz >= 6)
) {
  empfehlung = 'REAGIEREN';
} else if (relevanz >= 5 && empfehlung !== 'REAGIEREN') {
  empfehlung = 'BEOBACHTEN';
} else if (
  relevanz <= 4 &&
  sprengstoff === 'KEINER' &&
  asArray(s.warnsignale).length === 0 &&
  !ungleichFlag
) {
  empfehlung = 'IGNORIEREN';
}

const ampelMap = {
  KEINER: '⚪',
  GERING: '🟡',
  MITTEL: '🟠',
  HOCH: '🔴'
};

const ampel = ampelMap[sprengstoff] || '⚪';

let reaktionNoetig = toBool(s.reaktionNoetig);

if (empfehlung === 'REAGIEREN') reaktionNoetig = true;
if (empfehlung === 'IGNORIEREN') reaktionNoetig = false;

const maxIntensityBySprengstoff = {
  KEINER: 2,
  GERING: 2,
  MITTEL: 4,
  HOCH: 5
};

let satireIntensity = toNumber(s.satireIntensity, 1);
satireIntensity = clamp(satireIntensity, 1, maxIntensityBySprengstoff[sprengstoff] || 2);

// ============================================================
// 5. SENSIBLE THEMEN ERKENNEN
// ============================================================

const sensitiveContextText = normalizeText([
  sourceText,
  sourceLock.affectedGroups.join(' '),
  s.kurzfassung,
  s.warumRelevant,
  s.begruendungBewertung,
  s.moeglicheSatirischeReaktion,
  s.satireBrief,
  s.visualMetaphor
].join(' '));

const sensitiveContext =
  /\b(minderjaehrig|minderjaehrige|kind|kinder|schueler|schuelerin|schuelerinnen|schuelern|behinderung|behindert|barrierefrei|barrierefreiheit|blind|blinde|blinder|sehbehindert|taub|krank|pflege|rollstuhl|gefluechtet|wohnungslos|obdachlos|armut|opfer|notlage)\b/.test(sensitiveContextText);

function isAllowedSensitiveSachobjekt(text) {
  const n = normalizeText(text);

  return /\b(lichtsignalanlage|ampel|signalanlage|signalgeber|akustischer signalgeber|taster|tasterkasten|taktile bodenplatten|bodenplatten|leitstreifen|rampe|rollstuhlrampe|barrierefreier zugang|barrierefreier taster|bordsteinabsenkung|massnahmenplan|maßnahmenplan|fussgaengerfurt|fussgaengerueberweg|querung|verkehrsinsel)\b/.test(n);
}

function containsSensitivePerson(text) {
  const n = normalizeText(text);
  if (!n) return false;
  if (isAllowedSensitiveSachobjekt(n)) return false;

  return /\b(blinder|blinde|blindem|blinden|sehbehinderter|sehbehinderte|sehbehinderten|mensch mit behinderung|menschen mit behinderung|behinderter|behinderte|behinderten|schueler|schuelerin|schuelerinnen|schuelern|kind|kinder|minderjaehriger|minderjaehrige|patient|patientin|pflegebeduerftiger|pflegebeduerftige|rollstuhlfahrer|gefluechteter|gefluechtete|wohnungsloser|wohnungslose|obdachloser|obdachlose|kranker|kranke)\b/.test(n);
}

function containsSensitiveScene(text) {
  const n = normalizeText(text);
  if (!n || !sensitiveContext) return false;

  if (/\b(ein|eine|der|die|gruppe|gruppe von|mehrere|kleine gruppe)\s+(blinder|blinde|blindem|blinden|sehbehinderter|sehbehinderte|sehbehinderten|schueler|schuelerin|schuelerinnen|kind|kinder|rollstuhlfahrer|behinderte|behinderten)\b/.test(n)) {
    return true;
  }

  if (/\b(blinder|blinde|blinden|sehbehinderte|sehbehinderten|schueler|schuelerin|schuelerinnen|kind|kinder|rollstuhlfahrer|behinderte|behinderten)\b.{0,90}\b(tippt|drueckt|zeigt|stehen|steht|warten|wartet|laufen|laeuft|irren|irrt|suchen|sucht|stolpern|stolpert|queren|ueberqueren)\b/.test(n)) {
    return true;
  }

  if (/\b(blinde|blinder|blinden|sehbehinderte|schueler|kinder|rollstuhlfahrer|behinderte)\b.{0,120}\b(gefahr|gefaehrdet|verunsichert|hilflos|panik|panisch|unfall|verkehrschaos|risiko|dramatisch)\b/.test(n)) {
    return true;
  }

  return false;
}

function containsSensitiveMetaphor(text) {
  const n = normalizeText(text);
  if (!n || !sensitiveContext) return false;

  if (/\bblind(e|er|es|en)?\s+(sparschwein|haushalt|verwaltung|planung|politik|ampel|stadt|verfahren|rathaus)\b/.test(n)) return true;

  if (/\b(taub(e|er|es|en)?|lahm(e|er|es|en)?|krank(e|er|es|en)?|hilflos(e|er|es|en)?)\s+(verwaltung|planung|haushalt|politik|ampel|stadt|verfahren|rathaus)\b/.test(n)) return true;

  if (/barrierefreiheit.{0,60}\b(luxus|spass|spasz|spaß|teurer spass|teurer spasz|teurer spaß|uebertriebene forderung|übertriebene forderung)\b/.test(n)) return true;

  return false;
}

// ============================================================
// 6. SYMBOL-DRIFT ERKENNEN
// ============================================================

const forbiddenSymbolRe =
  /\b(sparschwein|geldsack|waage|aktenberg|rathaus|nebel|monster|hai|haie|marionette|marionetten|theaterbuehne|theaterbühne|theater|clown|clowns|maskottchen)\b/;

function sourceContainsExactTerm(term) {
  const n = normalizeText(term);
  if (!n || n.length < 3) return false;
  return sourceNorm.includes(n);
}

function isForbiddenSymbolObject(text) {
  const n = normalizeText(text);
  if (!n) return false;
  if (!forbiddenSymbolRe.test(n)) return false;

  return !sourceContainsExactTerm(text);
}

const genericObjectSet = new Set([
  'stadt',
  'verwaltung',
  'politik',
  'buerokratie',
  'bürokratie',
  'gerechtigkeit',
  'haushalt',
  'kosten',
  'finanzierung',
  'massnahme',
  'maßnahme',
  'verfahren',
  'gremium',
  'beschluss',
  'antrag',
  'vorlage',
  'thema',
  'konflikt',
  'situation',
  'problem',
  'prioritaet',
  'priorität',
  'zustaendigkeit',
  'zuständigkeit',
  'planung',
  'umsetzung'
].map(normalizeText));

function isConcreteObject(text) {
  const n = normalizeText(text);
  if (!n || n.length < 3) return false;
  if (genericObjectSet.has(n)) return false;
  if (isForbiddenSymbolObject(text)) return false;
  if (sensitiveContext && containsSensitivePerson(text)) return false;
  return true;
}

function concreteCount(arr) {
  return asArray(arr).filter(isConcreteObject).length;
}

// ============================================================
// 7. FORBIDDENDRIFT BEREINIGEN
// ============================================================

const genuineParts = new Set([
  'finanzierung',
  'haushalt',
  'kosten',
  'haushaltsreste',
  'haushaltsrest',
  'massnahme',
  'maßnahme',
  'ort',
  'gremium',
  'sachobjekt',
  'einrichtung',
  'lichtsignalanlage',
  'ampel',
  'signalgeber',
  'taster',
  'tasterkasten',
  'bodenplatten',
  'leitstreifen',
  'barrierefreiheit',
  'barrierefrei',
  'heinerich pieper strasse',
  'heinrich pieper strasse',
  'berliner allee'
].map(normalizeText));

const requiredSet = new Set([
  ...sourceLock.requiredTerms,
  ...sourceLock.requiredObjects,
  sourceLock.requiredAction,
  visualAnchors.satireThemaKonkret,
  visualAnchors.visualOrt
].map(normalizeText).filter(Boolean));

sourceLock.forbiddenDrift = uniqueArray(sourceLock.forbiddenDrift).filter(d => {
  const n = normalizeText(d);
  if (!n) return false;
  if (genuineParts.has(n)) return false;
  if (requiredSet.has(n)) return false;
  return true;
});

const fallbackForbiddenDrift = [
  'allgemeine Rathaus-Satire ohne konkreten Vorgangsbezug',
  'allgemeiner Aktenberg als Hauptmotiv',
  'beliebiger Geldsack oder reine Finanzsymbolik als Hauptpointe',
  'Pointe auf Kosten schutzbedürftiger Betroffener',
  'Korruptionsunterstellung oder persönliche Schuldzuweisung'
];

for (const d of fallbackForbiddenDrift) {
  if (sourceLock.forbiddenDrift.length >= 3) break;
  if (!sourceLock.forbiddenDrift.some(x => normalizeText(x) === normalizeText(d))) {
    sourceLock.forbiddenDrift.push(d);
  }
}

// ============================================================
// 8. VALIDIERUNG SOURCELOCK + VISUAL ANCHORS
// ============================================================

const sourceLockErrors = [];

if (!sourceLock.sourceTopic) {
  sourceLockErrors.push('sourceLock.sourceTopic fehlt');
}

if (!sourceLock.sourceConflict) {
  sourceLockErrors.push('sourceLock.sourceConflict fehlt');
}

if (sourceLock.requiredTerms.length < 2) {
  sourceLockErrors.push('sourceLock.requiredTerms enthält weniger als 2 Begriffe');
}

if (concreteCount(sourceLock.requiredObjects) < 2) {
  sourceLockErrors.push('sourceLock.requiredObjects enthält weniger als 2 konkrete Objekte');
}

if (!sourceLock.requiredAction) {
  sourceLockErrors.push('sourceLock.requiredAction fehlt');
}

const visualAnchorsErrors = [];

if (!visualAnchors.satireThemaKonkret) {
  visualAnchorsErrors.push('satireThemaKonkret fehlt');
}

if (!visualAnchors.satireKonfliktKonkret) {
  visualAnchorsErrors.push('satireKonfliktKonkret fehlt');
}

if (concreteCount(visualAnchors.visualPflichtobjekte) < 2) {
  visualAnchorsErrors.push('visualPflichtobjekte enthält weniger als 2 konkrete zeichnbare Objekte');
}

if (!visualAnchors.visualPflichthandlung) {
  visualAnchorsErrors.push('visualPflichthandlung fehlt');
}

if (!visualAnchors.visualErkennungssatz) {
  visualAnchorsErrors.push('visualErkennungssatz fehlt');
}

if (visualAnchors.visualVerboteneErsatzmotive.length < 2) {
  visualAnchorsErrors.push('visualVerboteneErsatzmotive enthält weniger als 2 Einträge');
}

// ============================================================
// 9. VISUAL GUARD
// ============================================================

const visualSceneText = [
  visualAnchors.visualPflichthandlung,
  visualAnchors.visualUeberzeichnung,
  visualAnchors.visualErkennungssatz,
  s.visualMetaphor,
  s.satireBrief,
  s.satireAngle,
  asArray(s.satirePunchlines).join(' '),
  s.moeglicheSatirischeReaktion
].map(safeStr).join(' ');

const visualGuardErrors = [];

const sensitivePersonObjects = [
  ...visualAnchors.visualPflichtobjekte,
  ...sourceLock.requiredObjects
].filter(x => sensitiveContext && containsSensitivePerson(x));

if (sensitivePersonObjects.length > 0) {
  visualGuardErrors.push(
    'Sensible Betroffene als Pflichtobjekt/sourceLock.requiredObject erkannt: ' +
    sensitivePersonObjects.join(', ')
  );
}

if (sensitiveContext && containsSensitiveScene(visualSceneText)) {
  visualGuardErrors.push(
    'Sensible Betroffene erscheinen in Visual- oder Satirefeldern als Bildszene/Pointe'
  );
}

if (sensitiveContext && containsSensitiveMetaphor(visualSceneText)) {
  visualGuardErrors.push(
    'Schutzlage wird als Metapher, Wortspiel oder Karikatureigenschaft verwendet'
  );
}

let visualBetroffeneCleared = false;

if (sensitiveContext && visualAnchors.visualBetroffene.length > 0) {
  visualAnchors.visualBetroffene = [];
  visualBetroffeneCleared = true;
}

const forbiddenSymbols = [
  ...visualAnchors.visualPflichtobjekte,
  ...sourceLock.requiredObjects
].filter(isForbiddenSymbolObject);

if (forbiddenSymbols.length > 0) {
  visualGuardErrors.push(
    'Symbol-Drift als Pflichtobjekt/sourceLock.requiredObject erkannt: ' +
    forbiddenSymbols.join(', ')
  );
}

const sourceLockValid = sourceLockErrors.length === 0;
const visualAnchorsValid = visualAnchorsErrors.length === 0;
const guardValid = visualGuardErrors.length === 0;

// ============================================================
// 10. VISUAL-FREIGABE
// ============================================================

const visualCandidate =
  empfehlung === 'REAGIEREN' &&
  kommunikationspotenzial >= 7;

const visualReady =
  visualCandidate &&
  sourceLockValid &&
  visualAnchorsValid &&
  guardValid;

let visualStatus = 'no_visual';
let instagramSharepicNoetig = false;
let instagramCarouselNoetig = false;
let visualNeeded = false;
let visualDecisionReason = '';

if (!visualCandidate) {
  visualStatus = 'no_visual';
  visualDecisionReason = 'Kein Sharepic nötig: Empfehlung oder Kommunikationspotenzial reichen nicht.';
} else if (visualReady) {
  visualStatus = 'visual_topic_ok';
  instagramSharepicNoetig = true;
  instagramCarouselNoetig = true;
  visualNeeded = true;
  visualDecisionReason = 'Sharepic freigegeben: SourceLock und Visual-Anker vollständig, keine sensible Betroffenen-Pointe, keine Symbol-Drift.';
} else {
  visualStatus = 'visual_topic_error';
  instagramSharepicNoetig = false;
  instagramCarouselNoetig = false;
  visualNeeded = false;

  const allErrors = [
    ...sourceLockErrors,
    ...visualAnchorsErrors,
    ...visualGuardErrors
  ];

  visualDecisionReason = 'Sharepic blockiert: ' + allErrors.join(' | ');
}

// ============================================================
// 10b. DOWNSTREAM-GUARD (P1/P2/P3 bereits fortgeschritten?)
// Verhindert, dass eine erneute Analyse (z.B. Re-Scrape/Vorgangskette)
// bereits von P1/P2/P3 weiterverarbeitete Zeilen zuruecksetzt.
// Gleiche Logik wie in ALLRIS_Repair_SourceLock_VisualGuard, erweitert um P3-Stufen.
// ============================================================

function hasP1Content(row) {
  if (safeStr(row.websiteHeadline)) return true;
  const cj = safeStr(row.contentJson);
  if (!cj || cj === '{}' || cj === 'null') return false;
  try {
    const p = JSON.parse(cj);
    return p && typeof p === 'object' && !Array.isArray(p) && Object.keys(p).length > 0;
  } catch (e) {
    return false;
  }
}

const ADVANCED_VISUAL_STATUS = [
  'needs_visual_prompt', 'awaiting_headline_choice', 'headline_selected',
  'visual_prompt_ready', 'visual_prompt_error', 'visual_prompt_topic_error',
  'blocked_by_source_lock', 'blocked_by_content_error', 'force_visual_reset',
  'image_composed', 'image_qa_approved', 'image_qa_error', 'image_qa_retry_required',
  'image_retry_required', 'image_quality_failed', 'nextcloud_upload_failed',
  'image_generation_error', 'image_prompt_error'
];

const downstreamProgressed = hasP1Content(rowData) || ADVANCED_VISUAL_STATUS.includes(safeStr(rowData.visualStatus));

if (downstreamProgressed) {
  visualStatus = safeStr(rowData.visualStatus) || visualStatus;
  instagramSharepicNoetig = rowData.instagramSharepicNoetig === true || rowData.instagramCarouselNoetig === true || rowData.visualNeeded === true;
  instagramCarouselNoetig = instagramSharepicNoetig;
  visualNeeded = instagramSharepicNoetig;
  visualDecisionReason = safeStr(rowData.visualDecisionReason) || 'Bereits von P1/P2/P3 weiterverarbeitet - visualStatus/status durch erneute Analyse nicht ueberschrieben.';
}

// ============================================================
// 11. FREIGABEEMPFEHLUNG
// ============================================================

const beweissicherheit = enumValue(
  s.beweissicherheit,
  ['NIEDRIG', 'MITTEL', 'HOCH'],
  'NIEDRIG'
);

const rechtlichesRisiko = enumValue(
  s.rechtlichesRisiko,
  ['NIEDRIG', 'MITTEL', 'HOCH'],
  'NIEDRIG'
);

let freigabeEmpfohlen = toBool(s.freigabeEmpfohlen);

if (
  empfehlung === 'REAGIEREN' &&
  beweissicherheit !== 'NIEDRIG' &&
  rechtlichesRisiko !== 'HOCH'
) {
  freigabeEmpfohlen = true;
}

if (
  rechtlichesRisiko === 'HOCH' ||
  beweissicherheit === 'NIEDRIG'
) {
  freigabeEmpfohlen = false;
}

// ============================================================
// 12. STATUS
// ============================================================

let status = 'watching';

if (empfehlung === 'IGNORIEREN') status = 'ignored';
if (empfehlung === 'BEOBACHTEN') status = 'watching';
if (empfehlung === 'REAGIEREN') status = 'needs_content';

if (downstreamProgressed) {
  status = safeStr(rowData.status) || status;
}

// ============================================================
// 13. NORMALISIERTES ANALYSISJSON
// ============================================================

const normalizedAnalysis = {
  ...s,

  relevanz,
  kommunikationspotenzial,
  sprengstoff,
  empfehlung,
  reaktionNoetig,
  ampel,

  beweissicherheit,
  rechtlichesRisiko,
  freigabeEmpfohlen,

  satireIntensity,

  instagramCarouselNoetig,
  instagramSharepicNoetig,
  visualNeeded,
  visualStatus,

  sourceLock,
  sourceLockValid,
  sourceLockErrors,

  visualAnchors,
  visualAnchorsValid,
  visualAnchorsErrors,

  visualGuardErrors,
  sensitiveContext,
  visualBetroffeneCleared,

  visualWorkflow: {
    visualNeeded,
    visualStatus,
    workflowStatus: visualReady
      ? 'waiting_for_content'
      : (visualCandidate ? 'blocked_by_visual_guard' : 'no_visual'),
    visualDecisionReason,
    sourceLockValid,
    sourceLockErrors,
    visualAnchorsValid,
    visualAnchorsErrors,
    visualGuardErrors,
    sensitiveContext,
    visualBetroffeneCleared
  },

  visualDecisionReason
};

// ============================================================
// 13b. ORCHESTRATOR-MIGRATION DURCHGANG A: contentStage/visualStage/imageStage additiv
// Siehe ALLRIS_Orchestrator_Shadow.json "Berechne Pipeline-Stages" fuer die Referenzlogik.
// ============================================================

const CONTENT_ERROR = new Set(['detail_failed', 'metadata_error', 'analysis_error', 'summary_input_error', 'summary_parse_error', 'content_error']);
const CONTENT_DIRECT = { '': 'new', 'needs_summary': 'needs_summary', 'watching': 'watching', 'ignored': 'ignored', 'needs_content': 'needs_content', 'content_generated': 'content_generated', 'content_posted': 'content_posted', 'nextcloud_failed': 'needs_summary', 'nextcloud_failed_final': 'archiving_failed', 'nextcloud_archived': 'needs_summary' };
const IMAGE_VALUES = new Set(['image_composed', 'nextcloud_upload_failed', 'image_retrying', 'retry_required', 'image_qa_error', 'image_quality_failed', 'image_qa_approved', 'visual_concept_repairing', 'visual_concept_repair_failed', 'visual_prompt_ready', 'visual_topic_error_final', 'blocked_by_source_lock', 'image_qa_rechecking', 'force_image_refresh', 'force_image_reset', 'force_full_image_refresh', 'visual_prompt_failed_final', 'image_prompt_ready', 'image_retry_required', 'image_qa_retry_required', 'raw_generated', 'ready_for_composite']);
const VISUAL_DIRECT = { 'no_visual': 'not_applicable', 'visual_topic_ok': 'topic_ok', 'visual_topic_error': 'topic_error', 'blocked_by_content_error': 'blocked_content_error', 'blocked_by_source_lock': 'blocked_source_lock', 'waiting_for_content': 'waiting_for_content', 'needs_visual_prompt': 'needs_prompt', 'visual_prompt_ready': 'prompt_ready', 'visual_prompt_error': 'prompt_error', 'visual_prompt_topic_error': 'prompt_error', 'awaiting_headline_choice': 'awaiting_headline_choice', 'headline_selected': 'headline_selected', 'force_visual_reset': 'needs_prompt', 'visual_prompt_failed_final': 'prompt_failed_final' };
const IMAGE_DIRECT = { 'raw_generated': 'raw_generated', 'ready_for_composite': 'ready_for_composite', 'image_composed': 'composed', 'nextcloud_upload_failed': 'upload_failed', 'image_retrying': 'qa_pending', 'retry_required': 'qa_pending', 'image_retry_required': 'qa_pending', 'image_qa_error': 'qa_pending', 'image_qa_retry_required': 'qa_pending', 'image_qa_rechecking': 'qa_pending', 'image_quality_failed': 'qa_failed', 'image_qa_approved': 'qa_approved', 'visual_concept_repairing': 'concept_repairing', 'visual_concept_repair_failed': 'concept_repair_failed', 'visual_topic_error_final': 'topic_error_final' };
function mapContentStage(statusValue, wordpressPostedValue) {
  const st = String(statusValue || '').trim();
  if (CONTENT_ERROR.has(st)) return { stage: 'error', reason: st };
  if (Object.prototype.hasOwnProperty.call(CONTENT_DIRECT, st)) return { stage: CONTENT_DIRECT[st], reason: '' };
  if (IMAGE_VALUES.has(st)) {
    const posted = wordpressPostedValue === 'true' || wordpressPostedValue === true;
    return { stage: posted ? 'content_posted' : 'content_generated', reason: '' };
  }
  return { stage: 'unknown', reason: '' };
}
function mapVisualStage(visualStatusValue) {
  const vs = String(visualStatusValue || '').trim();
  if (Object.prototype.hasOwnProperty.call(VISUAL_DIRECT, vs)) return VISUAL_DIRECT[vs];
  if (IMAGE_VALUES.has(vs)) return 'prompt_ready';
  if (vs === '') return 'not_applicable';
  return 'unknown';
}
function mapImageStage(statusValue, visualStatusValue, imageFinalPathValue) {
  const st = String(statusValue || '').trim();
  const vs = String(visualStatusValue || '').trim();
  if (Object.prototype.hasOwnProperty.call(IMAGE_DIRECT, vs)) return IMAGE_DIRECT[vs];
  if (Object.prototype.hasOwnProperty.call(IMAGE_DIRECT, st)) return IMAGE_DIRECT[st];
  if (safeStr(imageFinalPathValue)) return 'composed';
  return 'not_started';
}

const mappedContent = mapContentStage(status, rowData.wordpressPosted);
const contentStageToWrite = mappedContent.stage;
const contentErrorReasonToWrite = mappedContent.reason;
const visualStageToWrite = mapVisualStage(visualStatus);
const imageStageToWrite = mapImageStage(status, visualStatus, rowData.imageFinalPath);

