// Prepare Analyse Input
// Gibt summaryText + Einordnungsfelder weiter.
// Fügt zusätzlich einen kurzen Warnwort-Auszug aus combinedText an,
// damit die Eskalationsregel für Ungleichbehandlung/Willkür zuverlässig greift.

// Robust: Nach Matrix/DataTable kann der aktuelle Input abgespeckt sein.
// Build Summary Message enthält die vollständige Originalzeile.
// Branch-sicherer Datenzugriff (BRANCH_SAFE_SUMMARY_FIX)
function getNodeJsonIfExecuted(nodeName) {
  try { return $(nodeName).item.json || {}; } catch (e) { return {}; }
}
const _bsmData = getNodeJsonIfExecuted('Build Summary Message');
const j = { ..._bsmData, ...$input.item.json };

const WARN_WORDS = [
  'ungleichbehandlung','ungleiche behandlung','benachteiligung',
  'willkür','willkuer','doppelstandard','sonderbehandlung','bevorzugung',
  'unterschiedliche maßstäbe','unterschiedliche massstäbe','unterschiedliche massstaebe',
  'fehlende gleichbehandlung',
  'nicht nachvollziehbar','intransparent','beschwerde','kritik an',
  'verwaltungshandeln','abweichend von','pflichtgemäßem ermessen','pflichtgemaessem ermessen',
  'auf antrag der verwaltung','rechtswidrig','widerspruch'
];

const fullText  = j.combinedText || '';
const lowerText = fullText.toLowerCase();

// Alle Warnwort-Treffer mit Kontext sammeln (je ±300 Zeichen)
const snippets = [];
const seen     = new Set();

for (const word of WARN_WORDS) {
  let pos = 0;
  while (pos < lowerText.length) {
    const idx = lowerText.indexOf(word, pos);
    if (idx === -1) break;
    const start  = Math.max(0, idx - 300);
    const end    = Math.min(fullText.length, idx + 400);
    const bucket = Math.floor(start / 500);   // Überlappungen vermeiden
    if (!seen.has(bucket)) {
      seen.add(bucket);
      snippets.push(fullText.slice(start, end).trim());
    }
    pos = idx + word.length;
    if (snippets.length >= 8) break;          // max. 8 Snippets
  }
  if (snippets.length >= 8) break;
}

// Erste 1.500 Zeichen immer nehmen (enthält oft Beschlusstext + Kernaussage)
const docStart = fullText.substring(0, 1500).trim();

let warnContext = '';
if (snippets.length > 0) {
  warnContext = '\n\n--- Auszüge mit Warnsignalen aus Dokumenttext ---\n' +
    snippets.map((s, i) => `[${i+1}] …${s}…`).join('\n\n');
}

const analyseContext = docStart
  ? '\n\n--- Anfang Dokumenttext (erste 1.500 Zeichen) ---\n' + docStart
  : '';

// Gesamtlänge begrenzen (~3.000 Zeichen Zusatzkontext)
const extra = (analyseContext + warnContext).substring(0, 3000);

return [{
  json: {
    ...j,
    analyseContext: extra,
    warnSnippetCount: snippets.length,
    analyseContextLength: extra.length
  }
}];

const raw = $input.all();

// Input kann Array-in-Array sein je nach Loop-Node-Verhalten
let items_to_process = [];
for (const item of raw) {
  const j = item.json;
  if (Array.isArray(j)) {
    // Loop gab Array als json zurück → jedes Element einzeln
    for (const el of j) {
      items_to_process.push(typeof el === 'object' && el !== null ? el : {});
    }
  } else if (j && typeof j === 'object') {
    items_to_process.push(j);
  }
}

if (items_to_process.length === 0) {
  return [{ json: { _error: 'no_valid_input' } }];
}

function extractYear(val) {
  if (!val) return null;
  const m = String(val).match(/\b(20\d{2})\b/);
  return m ? m[1] : null;
}

return items_to_process.map(j => {
  const year = extractYear(j.firstseen)
    || extractYear(j.lastseen)
    || extractYear(j.summaryCreatedAt)
    || new Date().getFullYear().toString();

  let base = (j.nextcloudFolder || '').trim().replace(/\/+$/, '');
  let nc_originale_path;

  if (base.startsWith('/DiePARTEI/Allris/')) {
    nc_originale_path = base.endsWith('/01_originale') ? base : base + '/01_originale';
  } else if (base.endsWith('/01_originale')) {
    nc_originale_path = '/DiePARTEI/Allris/' + year + '/' + base;
  } else if (base !== '') {
    nc_originale_path = '/DiePARTEI/Allris/' + year + '/' + base + '/01_originale';
  } else {
    const vgnr = (j.vorgangKey || 'unbekannt').replace(/\//g, '_');
    nc_originale_path = '/DiePARTEI/Allris/' + year + '/' + vgnr + '/01_originale';
  }

  // Doppelte Slashes entfernen
  nc_originale_path = nc_originale_path.replace(/\/+/g, '/');

  return { json: { ...j, nc_originale_path, _ncYear: year } };
});

// NC Split Dateien – V11.7 NON-PDF SAFE
// Nur echte PDF-Kandidaten werden in den Download-/Tika-Loop gegeben.
// Bilder und andere Dateitypen werden sauber übersprungen und niemals an Tika gesendet.
// Modus: Run Once for All Items.

const base = $('Prepare Summary Input').item.json;
const nc_originale_path = $input.first()?.json?.nc_originale_path || '';

function safeStr(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

function decodePath(rawPath) {
  try { return decodeURIComponent(rawPath); }
  catch (e) { return rawPath; }
}

function getName(item) {
  const rawPath = safeStr(item?.json?.path || item?.json?.name);
  const decodedPath = decodePath(rawPath);
  return decodedPath.split('/').pop() || safeStr(item?.json?.name);
}

function getExtension(name) {
  const m = safeStr(name).toLowerCase().match(/\.([a-z0-9]+)$/i);
  return m ? m[1] : '';
}

const allFiles = items.filter(i => {
  const type = safeStr(i?.json?.type).toLowerCase();
  // Nextcloud liefert normalerweise type=file. Falls type fehlt, reicht ein Dateiname mit Endung.
  const name = getName(i);
  return type === 'file' || (!type && /\.[a-z0-9]{1,8}$/i.test(name));
});

const pdfFiles = [];
const skippedFiles = [];

for (const item of allFiles) {
  const name = getName(item);
  const ext = getExtension(name);

  if (ext === 'pdf') {
    pdfFiles.push(item);
  } else {
    skippedFiles.push({
      name,
      extension: ext || 'ohne_endung',
      reason: 'non_pdf_skipped'
    });
  }
}

const skippedNonPdfFiles = skippedFiles.map(f => f.name);
const skippedNonPdfCount = skippedFiles.length;

if (pdfFiles.length === 0) {
  return [{
    json: {
      ...base,
      nc_originale_path,
      combinedText: '',
      combinedTextLength: 0,
      _docCount: 0,
      pdfFilesFound: 0,
      pdfFilesExtracted: 0,
      pdfExtractErrors: 0,
      skippedNonPdfCount,
      skippedNonPdfFiles,
      summaryInputOk: false,
      summaryInputProblem: 'no_pdf_found',
      summaryInputSource: 'nextcloud_no_pdf'
    }
  }];
}

const currentVorgangKey = safeStr(base.vorgangKey);
const ncLoopBatchId = `${currentVorgangKey}::${$runIndex}`;

return pdfFiles.map(f => {
  const rawPath = safeStr(f.json.path || f.json.name);
  const decodedPath = decodePath(rawPath);
  const name = decodedPath.split('/').pop();
  const ncFilePath = '/' + decodedPath.replace(/^\/+/, '');

  return {
    json: {
      ...base,
      nc_originale_path,
      _ncFileName: name,
      _ncFilePath: ncFilePath,
      _ncExpectedType: 'pdf',
      _ncLoopInit: true,
      _ncLoopVorgangKey: currentVorgangKey,
      _ncLoopBatchId: ncLoopBatchId,
      skippedNonPdfCount,
      skippedNonPdfFiles
    }
  };
});

// NC Handle PDF Text – V11.7 NON-PDF SAFE
// Normalisiert genau ein Dokument-Ergebnis.
// Modus: Run Once for Each Item.

const j = $json || {};

// A) Bewusst übersprungene Datei: kein Parse-Fehler und kein Tika-Aufruf.
if (j.sendToTika === false && j.textExtractionSkipped === true) {
  return {
    json: {
      ...j,
      _ncLoopInit: false,
      _textExtracted: false,
      _pdfText: '',
      _extractReason: j.textExtractionMethod || 'file_skipped',
      _extractSkipped: true,
      textExtractionSuccess: false,
      textLength: 0,
      textExtractionError: j.textExtractionError || ''
    }
  };
}

// B) Technischer Download-/Binary-Fehler.
if (j.sendToTika === false) {
  return {
    json: {
      ...j,
      _ncLoopInit: false,
      _textExtracted: false,
      _pdfText: '',
      _extractReason: j.textExtractionMethod || 'download_failed',
      _extractSkipped: false,
      textExtractionSuccess: false,
      textLength: 0,
      textExtractionError: j.textExtractionError || 'Datei konnte nicht verarbeitet werden'
    }
  };
}

// C) Tika-Ergebnis.
const tikaError = String(j.tikaError || j.error?.message || '').trim();

const rawText =
  typeof j.tikaText === 'string' ? j.tikaText :
  typeof j.data === 'string' ? j.data :
  typeof j.body === 'string' ? j.body :
  '';

const text = rawText.trim();

let _textExtracted = false;
let _extractReason = '';
let _pdfText = '';
let textExtractionSuccess = false;
let textExtractionMethod = '';
let textExtractionError = '';

if (text.length >= 30) {
  _textExtracted = true;
  _extractReason = 'ok';
  _pdfText = text;
  textExtractionSuccess = true;
  textExtractionMethod = 'tika_pdf';
} else if (tikaError) {
  _extractReason = 'tika_error';
  textExtractionMethod = 'tika_error';
  textExtractionError = tikaError;
} else if (text.length > 0) {
  _extractReason = 'tika_too_short';
  textExtractionMethod = 'tika_too_short';
  textExtractionError = `Tika lieferte nur ${text.length} Zeichen (Minimum: 30)`;
} else {
  _extractReason = 'tika_empty';
  textExtractionMethod = 'tika_empty';
  textExtractionError = 'Tika lieferte keinen Dokumenttext';
}

return {
  json: {
    ...j,
    _ncLoopInit: false,
    _textExtracted,
    _pdfText,
    _extractReason,
    _extractSkipped: false,
    textExtractionSuccess,
    textExtractionMethod,
    textLength: text.length,
    textExtractionError
  }
};

// NC Aggregiere Texte – V11.7 NON-PDF SAFE
// Fasst alle PDF-Ergebnisse eines Vorgangs zusammen.
// Bewusst übersprungene Nicht-PDF-/Bilddateien gelten nicht als Parse- oder Extraktionsfehler.
// Modus: Run Once for All Items.

const inputItems = $input.all(0, $runIndex);
if (!Array.isArray(inputItems) || inputItems.length === 0) return [];

function safeStr(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

function getVorgangKey(item) {
  const j = item?.json || {};
  const direct = safeStr(j.vorgangKey || j._ncLoopVorgangKey);
  if (direct) return direct;
  const batchId = safeStr(j._ncLoopBatchId);
  return batchId.includes('::') ? batchId.split('::')[0].trim() : '';
}

const noPdfItem = inputItems.find(item => item?.json?.summaryInputProblem === 'no_pdf_found');
const hasDocumentResult = inputItems.some(item => {
  const j = item?.json || {};
  return Boolean(j._ncFilePath || j._ncFileName || j._textExtracted !== undefined || j._pdfText);
});

if (noPdfItem && !hasDocumentResult) {
  const base0 = noPdfItem.json || {};
  return [{
    json: {
      ...base0,
      combinedText: '',
      combinedTextLength: 0,
      pdfFilesFound: 0,
      pdfFilesExtracted: 0,
      pdfExtractErrors: 0,
      skippedPdfCandidates: 0,
      skippedNonPdfCount: Number(base0.skippedNonPdfCount || 0),
      skippedNonPdfFiles: Array.isArray(base0.skippedNonPdfFiles) ? base0.skippedNonPdfFiles : [],
      summaryInputOk: false,
      summaryInputProblem: 'no_pdf_found',
      summaryInputSource: 'nextcloud_no_pdf'
    }
  }];
}

let currentVorgangKey = '';
for (let i = inputItems.length - 1; i >= 0; i--) {
  const key = getVorgangKey(inputItems[i]);
  if (key) { currentVorgangKey = key; break; }
}

const onlyEmptyControlItems = inputItems.every(item => {
  const j = item?.json || {};
  return !getVorgangKey(item) && !j._ncLoopBatchId && !j._ncFileName && !j._ncFilePath &&
         !j.summaryInputProblem && !j._pdfText && j._textExtracted === undefined;
});

if (!currentVorgangKey) {
  if (onlyEmptyControlItems) return [];
  throw new Error(`NC Aggregiere Texte: Eingangsitem ohne vorgangKey. runIndex=${$runIndex} items=${inputItems.length}`);
}

let currentBatchId = '';
for (let i = inputItems.length - 1; i >= 0; i--) {
  const j = inputItems[i]?.json || {};
  const batchId = safeStr(j._ncLoopBatchId);
  if (batchId && getVorgangKey(inputItems[i]) === currentVorgangKey) {
    currentBatchId = batchId;
    break;
  }
}

let currentItems = inputItems.filter(item => {
  const j = item?.json || {};
  const sameVorgang = getVorgangKey(item) === currentVorgangKey;
  const sameBatch = !currentBatchId || j._ncLoopBatchId === currentBatchId;
  return sameVorgang && sameBatch;
});
if (currentItems.length === 0) {
  currentItems = inputItems.filter(item => getVorgangKey(item) === currentVorgangKey);
}

const documentItems = currentItems.filter(item => {
  const j = item?.json || {};
  return Boolean(j._ncFilePath || j._ncFileName || j._textExtracted !== undefined || j._pdfText);
});

const seenKeys = new Set();
const dedupedItems = [];
let fallbackIndex = 0;
for (const item of documentItems) {
  const j = item?.json || {};
  const dedupeKey = safeStr(j._ncFilePath || j._ncFileName || `${currentVorgangKey}::fallback::${fallbackIndex++}`);
  if (!seenKeys.has(dedupeKey)) {
    seenKeys.add(dedupeKey);
    dedupedItems.push(item);
  }
}

const baseItem =
  currentItems.find(item => item?.json?.title && getVorgangKey(item)) ||
  currentItems[0] || inputItems[0];
const base = baseItem?.json || {};

const nc_originale_path =
  currentItems.find(item => item?.json?.nc_originale_path)?.json?.nc_originale_path ||
  base.nc_originale_path || '';

const textItems = dedupedItems.filter(item => {
  const j = item?.json || {};
  return j._textExtracted === true && safeStr(j._pdfText) !== '';
});

const skippedItems = dedupedItems.filter(item => {
  const j = item?.json || {};
  return j._extractSkipped === true || j.textExtractionSkipped === true;
});

const errorItems = dedupedItems.filter(item => {
  const j = item?.json || {};
  return j._textExtracted !== true && j._extractSkipped !== true && j.textExtractionSkipped !== true;
});

const pdfFilesFound = dedupedItems.length;
const pdfFilesExtracted = textItems.length;
const pdfExtractErrors = errorItems.length;
const skippedPdfCandidates = skippedItems.length;

const parts = textItems.map(item => {
  const j = item.json || {};
  const fileName = safeStr(j._ncFileName) || 'unbekannt';
  const text = safeStr(j._pdfText);
  return `--- Dokument: ${fileName} ---\n${text}`;
});

const combinedText = parts.join('\n\n').slice(0, 60000);
const combinedTextLength = combinedText.length;
const combinedTextLower = combinedText.toLowerCase();
const placeholderTerms = [
  '(kein dokumenttext',
  '(dokumentlinks gefunden, aber kein dokumenttext extrahierbar)',
  'kein text extrahiert',
  'no text',
  'keine inhalte'
];
const isPlaceholder = placeholderTerms.some(term => combinedTextLower.includes(term));

let summaryInputOk = false;
let summaryInputProblem = '';
let summaryInputSource = 'nextcloud_tika_pdf';

if (pdfFilesFound === 0) {
  summaryInputProblem = 'no_pdf_found';
  summaryInputSource = 'nextcloud_no_pdf';
} else if (pdfFilesExtracted === 0) {
  summaryInputProblem = skippedPdfCandidates === pdfFilesFound
    ? 'no_valid_pdf_content'
    : 'document_text_error';
  summaryInputSource = 'nextcloud_tika_failed';
} else if (combinedTextLength < 300 || isPlaceholder) {
  summaryInputProblem = 'combined_text_too_short';
  summaryInputSource = 'nextcloud_tika_failed';
} else {
  summaryInputOk = true;
}

const skippedNonPdfCount = Math.max(...currentItems.map(i => Number(i?.json?.skippedNonPdfCount || 0)), 0);
const skippedNonPdfFiles = currentItems.find(i => Array.isArray(i?.json?.skippedNonPdfFiles))?.json?.skippedNonPdfFiles || [];

return [{
  json: {
    ...base,
    vorgangKey: currentVorgangKey,
    nc_originale_path,
    combinedText,
    combinedTextLength,
    pdfFilesFound,
    pdfFilesExtracted,
    pdfExtractErrors,
    skippedPdfCandidates,
    skippedNonPdfCount,
    skippedNonPdfFiles,
    summaryInputOk,
    summaryInputProblem: summaryInputOk ? '' : summaryInputProblem,
    summaryInputSource
  }
}];

const raw = $input.item.json;
const s = Array.isArray(raw) ? (raw[0] || {}) : (raw || {});
const now = new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

let summary = {};
try { summary = JSON.parse(s.summaryJson || '{}'); } catch(e) {}
let analyse = {};
try { analyse = JSON.parse(s.analysisJson || '{}'); } catch(e) {}

function toList(val) {
  if (Array.isArray(val)) return val.map(v => '- ' + v).join('\n');
  if (typeof val === 'string' && val) return val.split(/\s*\|\s*/).map(v => '- ' + v).join('\n');
  return '';
}

// Pfad berechnen
function extractYear(val) {
  const m = String(val || '').match(/\b(20\d{2})\b/);
  return m ? m[1] : new Date().getFullYear().toString();
}
const year = extractYear(s.firstseen || s.lastseen);
let base = (s.nextcloudFolder || '')
  .trim().replace(/\/+$/, '').replace(/\/01_originale$/, '');

let nc_base_path;
if (base.startsWith('/DiePARTEI/Allris/')) {
  nc_base_path = base;
} else if (base) {
  nc_base_path = '/DiePARTEI/Allris/' + year + '/' + base;
} else {
  nc_base_path = '/DiePARTEI/Allris/' + year + '/' + (s.vorgangKey || 'unbekannt').replace(/\//g, '_');
}
nc_base_path = nc_base_path.replace(/\/+/g, '/');
const nc_summary_path = nc_base_path + '/03_zusammenfassung';
const fileName = (s.vorgangKey || 'zusammenfassung').replace(/[\/\s]/g, '_') + '_zusammenfassung.md';


// ── Vorgangskette-Abschnitt (nur bei Folgevorgängen) ────────────────────────
let vorgangsketteMd = '';

if (s.istFolgevorgang === true || String(s.istFolgevorgang || '').trim() === 'true') {
  const details = Array.isArray(s.vorgangsketteDetails) ? s.vorgangsketteDetails : [];
  const fehlend = Array.isArray(s.fehlendeVorherigeVorgaenge) ? s.fehlendeVorherigeVorgaenge : [];
  const vollstaendig = s.vorgangsketteVollstaendig === true;

  const mdLines = [
    '',
    '## Bezug zu vorherigen Vorgängen',
    '',
    `**Stammvorgang:** ${s.stammVorgangsnummer || ''}`,
    `**Vorgangskette vollständig:** ${vollstaendig ? 'Ja' : 'Nein'}`,
    ''
  ];

  const mitKontext    = details.filter(d => d.gefunden && d.kontextVerwendet);
  const ohneKontext   = details.filter(d => d.gefunden && !d.kontextVerwendet);

  if (mitKontext.length > 0) {
    mdLines.push('### Berücksichtigte Vorgänge', '');
    for (const d of mitKontext) {
      const quelleText = d.kontextQuelle === 'summary'
        ? 'vorhandene Zusammenfassung'
        : 'Dokumenttext als Fallback';
      const link = d.allrisUrl ? `[${d.vorgangsnummer}](${d.allrisUrl})` : d.vorgangsnummer;
      mdLines.push(`* ${link} – ${quelleText}`);
    }
    mdLines.push('');
  }

  if (ohneKontext.length > 0) {
    mdLines.push('### Gefunden, aber in diesem Lauf nicht als Kontext verfügbar', '');
    for (const d of ohneKontext) {
      mdLines.push(`* ${d.vorgangsnummer}`);
    }
    mdLines.push('');
  }

  if (fehlend.length > 0) {
    mdLines.push('### Fehlende Vorgänge', '');
    for (const vn of fehlend) {
      mdLines.push(`* ${vn}`);
    }
    mdLines.push('');
  }

  vorgangsketteMd = mdLines.join('\n');
}

const md = [
  '# ' + (s.title || s.vorgangKey || ''),
  '',
  '| | |',
  '|---|---|',
  '| **Vorgangsnummer** | ' + (s.vorgangsnummer || '') + ' |',
  '| **ALLRIS-Link** | ' + (s.allrisUrl || '') + ' |',
  '| **Erstellt** | ' + now + ' |',
  '| **Ampel** | ' + (s.ampel || analyse.ampel || '') + ' |',
  '| **Sprengstoff** | ' + (s.sprengstoff || analyse.sprengstoff || '') + ' |',
  '| **Empfehlung** | ' + (s.empfehlung || analyse.empfehlung || '') + ' |',
  '| **Relevanz** | ' + (s.relevantScore || analyse.relevanz || '') + ' |',
  '',
  '---',
  '',
  ...(vorgangsketteMd ? [vorgangsketteMd, '---', ''] : []),
  '## Zusammenfassung',
  '',
  s.summaryText || summary.summaryText || '',
  '',
  '---',
  '',
  '## Thema',
  '',
  s.thema || summary.thema || '',
  '',
  '## Betroffene',
  '',
  toList(summary.betroffene || s.betroffene),
  '',
  '## Kosten / Haushalt',
  '',
  s.kostenHaushalt || summary.kostenHaushalt || '',
  '',
  '## Bürgerwirkung',
  '',
  s.buergerwirkung || summary.buergerwirkung || '',
  '',
  '## Offene Punkte',
  '',
  toList(summary.offenePunkte),
  '',
  '## Unsicherheiten',
  '',
  toList(summary.unsicherheiten || s.unsicherheitenSummary),
  '',
  '---',
  '',
  '## Bewertung',
  '',
  '**Kurzfassung:** ' + (s.kurzfassung || analyse.kurzfassung || ''),
  '',
  '**Kritische Nachfrage:** ' + (s.kritischeNachfrage || analyse.kritischeNachfrage || ''),
  '',
  '**Begründung:** ' + (s.begruendungBewertung || analyse.begruendungBewertung || ''),
  '',
  '**Wer profitiert:** ' + (s.werProfitiert || analyse.werProfitiert || ''),
  '',
  '**Wer trägt Nachteile:** ' + (s.werZahltOderTraegtNachteile || analyse.werZahltOderTraegtNachteile || ''),
].join('\n');

return { json: { ...s, _mdContent: md, _mdFileName: fileName, nc_summary_path } };

// Prüft, ob combinedText aus der DataTable wirklich verwendbaren Dokumenttext enthält.
// >= 300 Zeichen und kein technischer Platzhalter -> direkt zur AI Zusammenfassung.
// Sonst -> Nextcloud/Tika-Fallback.
//
// Modus: Run Once for All Items

function cleanText(value) {
  return String(value == null ? '' : value)
    .replace(/\r/g, '')
    .trim();
}

function isTechnicalPlaceholder(value) {
  const text = cleanText(value);
  if (!text) return true;

  const normalized = text
    .toLowerCase()
    .replace(/[„“”"'`´]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  if (['null', 'undefined', 'n/a', 'na', 'leer'].includes(normalized)) {
    return true;
  }

  return (
    /^\(?dokumentlinks? gefunden,?\s*aber kein dokumenttext extrahierbar\)?[.!]?$/i.test(text) ||
    /^\(?kein dokumenttext extrahierbar\)?[.!]?$/i.test(text) ||
    /^\(?keine dokumenttexte? extrahierbar\)?[.!]?$/i.test(text) ||
    /^\(?kein verwertbarer dokumenttext\)?[.!]?$/i.test(text) ||
    /^vorgangsseite\b.*(?:fehler|nicht erreichbar|nicht geladen|leer)/i.test(text) ||
    /^(?:fehler|error|download fehlgeschlagen|extraktion fehlgeschlagen)\b/i.test(text)
  );
}

const out = [];

for (const item of items) {
  const j = item.json || {};
  const combinedText = cleanText(j.combinedText);
  const combinedTextLength = combinedText.length;
  const technicalPlaceholder = isTechnicalPlaceholder(combinedText);
  const ok = combinedTextLength >= 300 && !technicalPlaceholder;

  out.push({
    json: {
      ...j,
      combinedText,
      combinedTextLength,
      combinedTextIsTechnicalPlaceholder: technicalPlaceholder,
      summaryInputOk: ok,
      summaryInputSource: ok
        ? 'datatable_combinedText'
        : 'nextcloud_fallback_needed',
      summaryInputProblem: ok
        ? ''
        : (technicalPlaceholder
            ? 'combinedText_technical_placeholder'
            : 'combinedText_missing_or_too_short')
    }
  });
}

return out;

// Sortierung nach sachlicher ALLRIS-Reihenfolge:
// 1. Jahr aus Vorgangsnummer
// 2. Hauptnummer aus Vorgangsnummer
// 3. Folgenummer nach Bindestrich, z.B. 2026/196-01
// 4. volfdnr numerisch
// 5. firstseen als letzter Fallback

function safe(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

function parseDate(v) {
  if (!v) return 0;
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : 0;
}

function parseVolfdnr(v) {
  if (!v) return Infinity;
  const n = parseInt(String(v).replace(/[^0-9]/g, ''), 10);
  return Number.isFinite(n) ? n : Infinity;
}

function parseVorgangsnummer(v) {
  const s = safe(v);

  // Erwartet z.B.:
  // 2026/196
  // 2026/196-01
  // 2026/196-2
  const m = s.match(/^(\d{4})\/(\d+)(?:-(\d+))?/);

  if (!m) {
    return {
      year: Infinity,
      main: Infinity,
      sub: 0
    };
  }

  return {
    year: parseInt(m[1], 10),
    main: parseInt(m[2], 10),
    sub: m[3] ? parseInt(m[3], 10) : 0
  };
}

const items = $input.all();

items.sort((a, b) => {
  const ja = a.json || {};
  const jb = b.json || {};

  const vaNum = parseVorgangsnummer(ja.vorgangsnummer);
  const vbNum = parseVorgangsnummer(jb.vorgangsnummer);

  // Jahr aufsteigend
  if (vaNum.year !== vbNum.year) return vaNum.year - vbNum.year;

  // Hauptvorgangsnummer aufsteigend
  if (vaNum.main !== vbNum.main) return vaNum.main - vbNum.main;

  // Folge zuerst nach Stammvorgang:
  // 2026/196 kommt vor 2026/196-01,
  // 2026/196-01 kommt vor 2026/196-02
  if (vaNum.sub !== vbNum.sub) return vaNum.sub - vbNum.sub;

  // Fallback: volfdnr aufsteigend
  const volA = parseVolfdnr(ja.volfdnr);
  const volB = parseVolfdnr(jb.volfdnr);
  if (volA !== volB) return volA - volB;

  // Letzter Fallback: firstseen aufsteigend
  const firstA = parseDate(ja.firstseen);
  const firstB = parseDate(jb.firstseen);
  if (firstA !== firstB) return firstA - firstB;

  return safe(ja.vorgangKey).localeCompare(safe(jb.vorgangKey));
});

return items;

// Prepare Summary Input – V10.4
// Der aktuelle Vorgang ist bereits durch "Bereite Vorgangskette vor" angereichert.
// Hier nur noch Stammkontext-Kompatibilität sicherstellen und an AI übergeben.

const current = $input.item.json || {};

// Alle Felder sind bereits vorhanden (vorherigeVorgaenge, vorgangsketteKontext, etc.)
// Nur sicherstellen, dass isFollowUp korrekt gesetzt ist
const istFolgevorgang =
  current.istFolgevorgang === true ||
  String(current.istFolgevorgang || '').trim().toLowerCase() === 'true' ||
  (String(current.folgeNummer || '').trim() !== '');

return {
  json: {
    ...current,
    istFolgevorgang
  }
};

// Normalisiere Vorgangsbeziehung
// Wird direkt nach Loop Vorgänge ausgeführt.
// Erhält alle Felder des Datensatzes und normalisiert robust die drei Folgevorgang-Felder.
// Unterstützt Boolean und String für istFolgevorgang.

const current = $input.item.json || {};

const vorgangsnummer = String(current.vorgangsnummer || '').trim();

const match = vorgangsnummer.match(/^(\d{4})\s*\/\s*(\d+)(?:-(\d+))?$/);

let derivedStamm =
  String(current.stammVorgangsnummer || '').trim();

let derivedFolge =
  String(current.folgeNummer || '').trim();

let derivedIstFolgevorgang =
  current.istFolgevorgang === true ||
  String(current.istFolgevorgang || '').trim().toLowerCase() === 'true';

if (match) {
  const stammAusNummer = `${match[1]}/${match[2]}`;
  const folgeAusNummer = match[3] || '';

  if (!derivedStamm) {
    derivedStamm = stammAusNummer;
  }

  if (!derivedFolge && folgeAusNummer) {
    derivedFolge = folgeAusNummer;
  }

  if (folgeAusNummer) {
    derivedIstFolgevorgang = true;
  }
}

if (!derivedStamm) {
  derivedStamm = vorgangsnummer;
}

return {
  json: {
    ...current,
    stammVorgangsnummer: derivedStamm,
    folgeNummer:         derivedFolge,
    istFolgevorgang:     derivedIstFolgevorgang
  }
};

// NC Prüfe Binary – V11.7 NON-PDF SAFE
// Es werden ausschließlich technisch plausible PDFs an Tika weitergegeben.
// JPG, PNG, GIF, TIFF, ZIP, HTML und sonstige Binärdateien werden sauber übersprungen.
// Modus: Run Once for All Items.

async function checkItem(item, index) {
  const j = item.json || {};
  const binData = item.binary?.data;
  const mimeType = String(binData?.mimeType || '').toLowerCase();
  const ncFileName = String(j._ncFileName || '').trim();
  const ncFilePath = String(j._ncFilePath || '').trim();
  const vorgangKey = String(j.vorgangKey || '').trim();
  const lowerName = ncFileName.toLowerCase();
  const lowerPath = ncFilePath.toLowerCase();

  function skipped(method, reason, extra = {}) {
    console.warn(`[NC Prüfe Binary] Übersprungen. method=${method} vorgangKey=${vorgangKey} file=${ncFileName} mimeType=${mimeType}`);
    return {
      ...j,
      ...extra,
      sendToTika: false,
      textExtractionSkipped: true,
      textExtractionSuccess: false,
      textLength: 0,
      textExtractionMethod: method,
      textExtractionError: reason || ''
    };
  }

  function failed(method, reason, extra = {}) {
    console.warn(`[NC Prüfe Binary] Fehler. method=${method} vorgangKey=${vorgangKey} file=${ncFileName} mimeType=${mimeType}`);
    return {
      ...j,
      ...extra,
      sendToTika: false,
      textExtractionSkipped: false,
      textExtractionSuccess: false,
      textLength: 0,
      textExtractionMethod: method,
      textExtractionError: reason || ''
    };
  }

  // 1. Unerwartete Nicht-PDF-Dateien niemals an Tika senden.
  const hasPdfExtension = lowerName.endsWith('.pdf') || lowerPath.endsWith('.pdf');
  if (!hasPdfExtension) {
    return skipped('non_pdf_skipped', `Nicht-PDF-Datei wurde nicht verarbeitet: ${ncFileName || ncFilePath}`);
  }

  // 2. Binary-Feld vorhanden?
  if (!binData) {
    return failed('download_failed', 'Kein Binary-Feld im Nextcloud-Download vorhanden');
  }

  // 3. Buffer lesen.
  let buffer;
  try {
    buffer = await this.helpers.getBinaryDataBuffer(index, 'data');
  } catch (e) {
    return failed('binary_read_error', `Binary-Buffer nicht lesbar: ${e.message}`);
  }

  if (!buffer || buffer.length === 0) {
    return failed('binary_empty', 'Heruntergeladene Datei ist leer (0 Byte)');
  }

  // 4. Magic Bytes / Inhaltstyp erkennen.
  const first16 = buffer.slice(0, 16);
  const head1024 = buffer.slice(0, 1024).toString('latin1');
  const headLower = head1024.trimStart().toLowerCase();

  const isPdfMagic = head1024.includes('%PDF-');
  const isJpeg = first16[0] === 0xFF && first16[1] === 0xD8 && first16[2] === 0xFF;
  const isPng = first16.length >= 8 &&
    first16[0] === 0x89 && first16[1] === 0x50 && first16[2] === 0x4E && first16[3] === 0x47 &&
    first16[4] === 0x0D && first16[5] === 0x0A && first16[6] === 0x1A && first16[7] === 0x0A;
  const isGif = head1024.startsWith('GIF87a') || head1024.startsWith('GIF89a');
  const isTiff = (first16[0] === 0x49 && first16[1] === 0x49 && first16[2] === 0x2A && first16[3] === 0x00) ||
                 (first16[0] === 0x4D && first16[1] === 0x4D && first16[2] === 0x00 && first16[3] === 0x2A);
  const isPkZip = first16[0] === 0x50 && first16[1] === 0x4B;
  const isHtml = headLower.startsWith('<!doctype html') ||
                 headLower.startsWith('<html') ||
                 headLower.startsWith('<head') ||
                 headLower.startsWith('<body');

  if (isJpeg || isPng || isGif || isTiff || mimeType.startsWith('image/')) {
    return skipped(
      'image_skipped',
      `Datei trägt eine PDF-Endung, enthält aber Bilddaten und wird nicht an Tika gesendet (mimeType=${mimeType || 'unbekannt'})`,
      { detectedBinaryType: isJpeg ? 'jpeg' : isPng ? 'png' : isGif ? 'gif' : isTiff ? 'tiff' : 'image' }
    );
  }

  if (isPkZip || mimeType.includes('zip')) {
    return skipped('zip_skipped', `ZIP-/Office-Container wird in diesem PDF-Pfad nicht verarbeitet (mimeType=${mimeType || 'unbekannt'})`);
  }

  if (isHtml || mimeType.includes('text/html')) {
    return failed('html_received', `HTML-Fehlerseite statt PDF empfangen (mimeType=${mimeType || 'unbekannt'})`);
  }

  // 5. Eine .pdf-Datei ohne PDF-Signatur nicht an Tika schicken.
  if (!isPdfMagic) {
    return skipped(
      'invalid_pdf_skipped',
      `Datei besitzt die Endung .pdf, hat aber keine erkennbare PDF-Signatur (mimeType=${mimeType || 'unbekannt'})`
    );
  }

  console.log(`[NC Prüfe Binary] PDF OK. vorgangKey=${vorgangKey} file=${ncFileName} size=${buffer.length} mimeType=${mimeType}`);
  return {
    ...j,
    sendToTika: true,
    textExtractionSkipped: false,
    detectedBinaryType: 'pdf'
  };
}

const results = [];
for (let i = 0; i < items.length; i++) {
  try {
    const result = await checkItem.call(this, items[i], i);
    results.push({ json: result, binary: items[i].binary });
  } catch (e) {
    results.push({
      json: {
        ...items[i].json,
        sendToTika: false,
        textExtractionSkipped: false,
        textExtractionSuccess: false,
        textLength: 0,
        textExtractionMethod: 'binary_check_failed',
        textExtractionError: `Unerwarteter Prüfungsfehler: ${e.message}`
      },
      binary: items[i].binary
    });
  }
}

return results;

// NC Metadaten nach Tika – Modus: Run Once for Each Item
// Stellt Vorgangs- und Dokumentmetadaten nach dem Tika-HTTP-Aufruf wieder her.
// Das aktuelle Item ist die Tika-HTTP-Antwort.
// Die ursprünglichen Metadaten kommen aus dem verknüpften Eingangsitem
// des True-Zweigs der IF-Node "NC IF sendToTika?".

const meta = $('NC IF sendToTika?').item.json;

const tikaText =
  typeof $json.tikaText === 'string' ? $json.tikaText :
  typeof $json.data     === 'string' ? $json.data     :
  typeof $json.body     === 'string' ? $json.body     :
  '';

const tikaError =
  $json.error?.message ||
  $json.message        ||
  '';

return {
  json: {
    ...meta,
    sendToTika: true,
    tikaText,
    tikaError
  }
};

// Prüfe Metadaten – V10.1 METADATA_GUARD
// Modus: Run Once for Each Item

const j = $json || {};

const title          = String(j.title          || '').trim();
const vorgangsnummer = String(j.vorgangsnummer || '').trim();
const allrisUrl      = String(j.allrisUrl || j.sourceUrl || '').trim();
const volfdnr        = String(j.volfdnr        || '').trim();

const HTTP_ERROR_TITLE_RE = /^\s*(?:400[\s:-]+bad\s+request|401[\s:-]+unauthorized|403[\s:-]+forbidden|404[\s:-]+not\s+found|408[\s:-]+request\s+time[- ]?out|429[\s:-]+too\s+many\s+requests|500[\s:-]+internal\s+server\s+error|501[\s:-]+not\s+implemented|502[\s:-]+bad\s+gateway|503[\s:-]+service\s+unavailable|504[\s:-]+gateway\s*time[- ]?out)\s*$/i;

const TECH_ERROR_PHRASE_RE = /gateway\s*time[- ]?out|bad\s+gateway|service\s+unavailable|internal\s+server\s+error|request\s+time[- ]?out|upstream\s+timed\s+out|proxy\s+error|temporarily\s+unavailable|too\s+many\s+requests|serverfehler|nginx\s+error|cloudflare\s+error/i;

function isTechnicalTitle(value) {
  const text = String(value || '').trim();
  return HTTP_ERROR_TITLE_RE.test(text) || TECH_ERROR_PHRASE_RE.test(text);
}

const errors = [];

if (!title) {
  errors.push('title_missing');
} else if (isTechnicalTitle(title)) {
  errors.push('technical_title');
} else if (title === '(Vorgangsseite nicht geladen)') {
  errors.push('placeholder_title');
}

if (!/^\d{4}\/\d+(?:-\d+)?$/.test(vorgangsnummer)) {
  errors.push('invalid_vorgangsnummer');
}

if (!allrisUrl) {
  errors.push('allris_url_missing');
}

if (volfdnr && vorgangsnummer === volfdnr) {
  errors.push('volfdnr_used_as_vorgangsnummer');
}

return {
  json: {
    ...j,
    metadataValid:     errors.length === 0,
    metadataErrors:    errors,
    metadataErrorText: errors.join(', ')
  }
};

// Bereite Vorgangskette vor – V11.5
// Modus: Run Once for All Items
// Korrektur:
// - summaryText hat immer Vorrang.
// - Falls summaryText leer/nicht geliefert ist, wird summaryJson.summaryText genutzt.
// - Erst danach wird echter combinedText als Fallback verwendet.
// - Technische Platzhalter wie „Dokumentlinks gefunden, aber kein Dokumenttext extrahierbar“
//   gelten niemals als Dokumenttext.

function parseVorgangsnummer(v) {
  const m = String(v || '').trim().match(/^(\d{4})\/(\d+)(?:-(\d+))?$/);
  if (!m) return null;
  return {
    jahr: Number(m[1]),
    hauptnummer: Number(m[2]),
    folgeString: m[3] || '',
    folgeNumerisch: m[3] ? Number(m[3]) : 0,
    istFolgevorgang: Boolean(m[3]),
    stammVorgangsnummer: `${m[1]}/${m[2]}`,
    normalisiert: m[3] ? `${m[1]}/${m[2]}-${m[3]}` : `${m[1]}/${m[2]}`
  };
}

function normalizeVN(v) {
  const p = parseVorgangsnummer(v);
  return p ? p.normalisiert : String(v || '').trim();
}

function parseObject(value) {
  if (!value) return {};
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  try {
    const parsed = JSON.parse(String(value));
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
  } catch (e) {
    return {};
  }
}

function parseArray(value) {
  if (Array.isArray(value)) return value;
  if (!value) return [];
  try {
    const parsed = JSON.parse(String(value));
    return Array.isArray(parsed) ? parsed : [];
  } catch (e) {
    return [];
  }
}

function cleanText(value) {
  return String(value == null ? '' : value)
    .replace(/\r/g, '')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function isTechnicalPlaceholder(value) {
  const text = cleanText(value);
  if (!text) return true;

  const normalized = text
    .toLowerCase()
    .replace(/[„“”"'`´]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  if (['null', 'undefined', 'n/a', 'na', 'leer'].includes(normalized)) return true;

  return (
    /^\(?dokumentlinks? gefunden,? aber kein dokumenttext extrahierbar\)?[.!]?$/i.test(text) ||
    /^\(?kein dokumenttext extrahierbar\)?[.!]?$/i.test(text) ||
