  }

  const summaryText = getSummaryText(row);
  const combinedText = getCombinedText(row);

  let kontextQuelle = 'unavailable';
  let kontextStatus = 'previous_without_text';
  let kontextVerwendet = false;
  let textForContext = '';
  let diagnose = '';

  if (summaryText) {
    kontextQuelle = 'summary';
    kontextStatus = 'summary_available';
    kontextVerwendet = true;
    textForContext = summaryText;
  } else if (combinedText) {
    kontextQuelle = 'combined_text';
    kontextStatus = 'combined_text_fallback';
    kontextVerwendet = true;
    textForContext = combinedText;
  } else {
    const rawCombinedText = cleanText(row.combinedText);
