  }

  let textTrimmed = '';
  if (kontextVerwendet) {
    const remaining = Math.max(0, MAX_GESAMT - gesamtChars);
    const limit = Math.min(MAX_PER_ITEM, remaining);

    if (limit > 0) {
      if (textForContext.length > limit) {
        textTrimmed = textForContext.slice(0, limit) + '…';
        gekuerzt = true;
      } else {
        textTrimmed = textForContext;
      }
      gesamtChars += textTrimmed.length;
    } else {
