    if (!parsedKey && !parsedVn) return false;

    if (rowKey && parsedKey && rowKey !== parsedKey) return false;
    if (rowVn && parsedVn && rowVn !== parsedVn) return false;

    const contentFields = ['summaryText', 'thema', 'buergerwirkung', 'offenePunkte'];
    return contentFields.some(f => safeStr(parsed[f]).length > 10);
