const response = $json || {};
const original = $('Fakten-Shadow: Baue Eingabe').itemMatching($itemIndex).json || {};
const hasFakten = typeof response.sourceTopic === 'string';

const fakten = hasFakten ? response : {
  vorgangKey: safeStr(original.vorgangKey),
  vorgangsnummer: safeStr(original.vorgangsnummer),
  sourceTopic: '', sourceConflict: '', requiredTerms: [], requiredObjects: [],
  requiredAction: '', affectedGroups: [], concreteNumbers: [], responsibilities: [],
  documentType: '', quotesVerbatim: [],
  parseError: true,
  callFailed: true
};

// Vergleich gegen das bereits VOR der Sub-Workflow-Grenze extrahierte sourceLock (siehe Fakten-Shadow: Baue Eingabe) - kein KI-Urteil.
const oldSourceLock = {
  sourceTopic: safeStr(original.oldSourceTopic),
  requiredTerms: asArray(original.oldRequiredTerms),
  requiredObjects: asArray(original.oldRequiredObjects)
};

function normalizeText(v) {
  return safeStr(v).toLowerCase()
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
}
function stemLight(w) {
  return w.replace(/(ungen|ierung|heit|keit|schaft|tion|ieren|iere|iert|ung|lich|isch|ische|ischen|ischer|isches)$/, '').replace(/(en|er|em|es|e|n|s|t)$/, '');
}
function tokenOverlap(a, b) {
  const tokensA = normalizeText(a).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);
  const tokensB = normalizeText(b).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);
  if (tokensA.some(w => tokensB.includes(w))) return true;
  const rawA = normalizeText(a).replace(/[\W_]+/g, ''), rawB = normalizeText(b).replace(/[\W_]+/g, '');
  for (const tok of tokensA) { if (tok.length >= 5 && rawB.includes(tok)) return true; }
  for (const tok of tokensB) { if (tok.length >= 5 && rawA.includes(tok)) return true; }
  return false;
}

const oldRequiredTerms = asArray(oldSourceLock.requiredTerms);
const newRequiredTerms = asArray(fakten.requiredTerms);
const oldRequiredObjects = asArray(oldSourceLock.requiredObjects);
const newRequiredObjects = asArray(fakten.requiredObjects);

const termsMatched = newRequiredTerms.filter(t => oldRequiredTerms.some(o => tokenOverlap(t, o))).length;
const objectsMatched = newRequiredObjects.filter(t => oldRequiredObjects.some(o => tokenOverlap(t, o))).length;
const sourceTopicOverlap = (safeStr(oldSourceLock.sourceTopic) && safeStr(fakten.sourceTopic))
  ? tokenOverlap(oldSourceLock.sourceTopic, fakten.sourceTopic)
  : false;

const comparison = {
  sourceTopicOverlap: sourceTopicOverlap,
  requiredTermsMatched: termsMatched,
  requiredTermsOldCount: oldRequiredTerms.length,
  requiredTermsNewCount: newRequiredTerms.length,
  requiredObjectsMatched: objectsMatched,
  requiredObjectsOldCount: oldRequiredObjects.length,
  requiredObjectsNewCount: newRequiredObjects.length
};

return {
  json: {
    vorgangKey: safeStr(original.vorgangKey),
    sprengstoff: safeStr(original.sprengstoff) || 'GERING',
    faktenAgentJson: JSON.stringify(fakten),
    faktenComparisonJson: JSON.stringify(comparison)
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}

const fakten = parseObj($json.faktenAgentJson);

return {
  json: {
    vorgangKey: $json.vorgangKey,
    vorgangsnummer: safeStr(fakten.vorgangsnummer),
    sourceTopic: fakten.sourceTopic,
    sourceConflict: fakten.sourceConflict,
    requiredTerms: fakten.requiredTerms,
    requiredObjects: fakten.requiredObjects,
    requiredAction: fakten.requiredAction,
    affectedGroups: fakten.affectedGroups,
    concreteNumbers: fakten.concreteNumbers,
    responsibilities: fakten.responsibilities,
    documentType: fakten.documentType,
    quotesVerbatim: fakten.quotesVerbatim,
    sprengstoff: $json.sprengstoff
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArray(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

const response = $json || {};
const original = $('Satire-Shadow: Baue Eingabe').itemMatching($itemIndex).json || {};
const hasVariants = Array.isArray(response.variants) && response.variants.length > 0;

const result = hasVariants ? response : {
  vorgangKey: safeStr(original.vorgangKey),
  vorgangsnummer: safeStr(original.vorgangsnummer),
  variants: [],
  parseError: true,
  callFailed: true
};

return {
  json: {
    vorgangKey: safeStr(original.vorgangKey) || safeStr(response.vorgangKey),
    vorgangsnummer: safeStr(original.vorgangsnummer),
    satireAgentJson: JSON.stringify(result),
    sourceTopic: safeStr(original.sourceTopic),
    requiredObjects: asArray(original.requiredObjects),
    requiredAction: safeStr(original.requiredAction),
    affectedGroups: asArray(original.affectedGroups)
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}
function asArray(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

const satire = parseObj($json.satireAgentJson);
const variants = Array.isArray(satire.variants) ? satire.variants : [];
const chosen = variants.length > 1 ? variants[1] : (variants[0] || {});

return {
  json: {
    vorgangKey: $json.vorgangKey,
    vorgangsnummer: safeStr($json.vorgangsnummer),
    sourceTopic: safeStr($json.sourceTopic),
    requiredObjects: asArray($json.requiredObjects),
    requiredAction: safeStr($json.requiredAction),
    affectedGroups: asArray($json.affectedGroups),
    satireBrief: safeStr(chosen.satireBrief),
    satireAngle: safeStr(chosen.satireAngle),
    satirePunchlines: asArray(chosen.satirePunchlines),
    satireTarget: safeStr(chosen.satireTarget),
    satireIntensity: chosen.satireIntensity,
    satireDoNotClaim: asArray(chosen.satireDoNotClaim),
    satireSafetyNote: safeStr(chosen.satireSafetyNote),
    imageHeadline: safeStr(chosen.imageHeadline),
    imageSubline: safeStr(chosen.imageSubline)
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

const response = $json || {};
const original = $('Bild-Shadow: Baue Eingabe').itemMatching($itemIndex).json || {};
const hasPrompt = typeof response.imagePrompt === 'string' && response.imagePrompt.length > 0;

const result = hasPrompt ? response : {
  vorgangKey: safeStr(original.vorgangKey),
  parseError: true,
  callFailed: true
};

return {
  json: {
    vorgangKey: safeStr(original.vorgangKey) || safeStr(response.vorgangKey),
    bildAgentJson: JSON.stringify(result)
  }
};
